    fork
      process_ibex_icache_fifo();
      process_ibex_mem_intf_slave_fifo();
    join_none
  endtask

  virtual task process_ibex_icache_fifo();
    ibex_icache_core_item item;
    forever begin
      core_fifo.get(item);
